1	import { useState, useEffect } from "react";
2	import { Card } from "@/components/ui/card";
3	import { Button } from "@/components/ui/button";
4	import { Input } from "@/components/ui/input";
5	import { Label } from "@/components/ui/label";
6	import { Switch } from "@/components/ui/switch";
7	import { Badge } from "@/components/ui/badge";
8	import { Separator } from "@/components/ui/separator";
9	import { supabase } from "@/integrations/supabase/client";
10	import { useToast } from "@/hooks/use-toast";
11	import MFASetup from "@/components/auth/MFASetup";
12	import { InputOTP, InputOTPGroup, InputOTPSlot } from "@/components/ui/input-otp";
13	import { useLanguage } from "@/i18n/LanguageContext";
14	import {
15	  Shield,
16	  KeyRound,
17	  Smartphone,
18	  Eye,
19	  EyeOff,
20	  AlertTriangle,
21	  CheckCircle2,
22	  LogOut,
23	  Lock,
24	  Mail,
25	  Loader2,
26	} from "lucide-react";
27	import {
28	  Dialog,
29	  DialogContent,
30	  DialogHeader,
31	  DialogTitle,
32	  DialogDescription,
33	  DialogFooter,
34	} from "@/components/ui/dialog";
35	
36	
37	const SecurityTab = () => {
38	  const { toast } = useToast();
39	  const { t } = useLanguage();
40	
41	  // Password change state
42	  const [showChangePassword, setShowChangePassword] = useState(false);
43	  const [currentPassword, setCurrentPassword] = useState("");
44	  const [newPassword, setNewPassword] = useState("");
45	  const [confirmPassword, setConfirmPassword] = useState("");
46	  const [showNew, setShowNew] = useState(false);
47	  const [showConfirm, setShowConfirm] = useState(false);
48	  const [changingPassword, setChangingPassword] = useState(false);
49	
50	  // 2FA state
51	  const [twoFactorEnabled, setTwoFactorEnabled] = useState(false);
52	  const [twoFaView, setTwoFaView] = useState<"idle" | "setup" | "disabling" | "disabling-sent">("idle");
53	  const [twoFaEmail, setTwoFaEmail] = useState("");
54	  const [twoFaDisableCode, setTwoFaDisableCode] = useState("");
55	  const [twoFaDisabling, setTwoFaDisabling] = useState(false);
56	  const [twoFaSending, setTwoFaSending] = useState(false);
57	
58	  const [loginAlertsEnabled, setLoginAlertsEnabled] = useState(true);
59	
60	  // Sign out all devices dialog
61	  const [showSignOutAll, setShowSignOutAll] = useState(false);
62	  const [signingOut, setSigningOut] = useState(false);
63	
64	  // Load 2FA status on mount
65	  useEffect(() => {
66	    supabase.auth.getUser().then(({ data: { user } }) => {
67	      setTwoFactorEnabled(!!user?.user_metadata?.two_fa_enabled);
68	      if (user?.email) setTwoFaEmail(user.email);
69	    });
70	  }, []);
71	
72	  const startDisable2FA = async () => {
73	    setTwoFaSending(true);
74	    try {
75	      const { error } = await supabase.auth.signInWithOtp({
76	        email: twoFaEmail,
77	        options: { shouldCreateUser: false },
78	      });
79	      if (error) throw error;
80	      setTwoFaView("disabling-sent");
81	      toast({ title: "Code sent", description: `Check ${twoFaEmail} for your verification code.` });
82	    } catch (err: any) {
83	      toast({ title: "Error", description: err.message, variant: "destructive" });
84	    } finally {
85	      setTwoFaSending(false);
86	    }
87	  };
88	
89	  const confirmDisable2FA = async () => {
90	    if (twoFaDisableCode.length !== 6) return;
91	    setTwoFaDisabling(true);
92	    try {
93	      const { error } = await supabase.auth.verifyOtp({
94	        email: twoFaEmail,
95	        token: twoFaDisableCode,
96	        type: "email",
97	      });
98	      if (error) throw error;
99	
100	      await supabase.auth.updateUser({ data: { two_fa_enabled: false, two_fa_method: null } });
101	      setTwoFactorEnabled(false);
102	      setTwoFaView("idle");
103	      setTwoFaDisableCode("");
104	      toast({ title: "2FA disabled", description: "Two-factor authentication has been turned off." });
105	    } catch (err: any) {
106	      toast({ title: "Invalid code", description: "The code you entered is incorrect.", variant: "destructive" });
107	      setTwoFaDisableCode("");
108	    } finally {
109	      setTwoFaDisabling(false);
110	    }
111	  };
112	
113	  // Password strength checker
114	  const getPasswordStrength = (pw: string) => {
115	    let score = 0;
116	    if (pw.length >= 8) score++;
117	    if (/[A-Z]/.test(pw)) score++;
118	    if (/[a-z]/.test(pw)) score++;
119	    if (/[0-9]/.test(pw)) score++;
120	    if (/[^A-Za-z0-9]/.test(pw)) score++;
121	    if (score <= 2) return { label: "Weak", color: "text-destructive", bg: "bg-destructive" };
122	    if (score <= 3) return { label: "Fair", color: "text-yellow-500", bg: "bg-yellow-500" };
123	    if (score <= 4) return { label: "Strong", color: "text-emerald-500", bg: "bg-emerald-500" };
124	    return { label: "Very Strong", color: "text-emerald-600", bg: "bg-emerald-600" };
125	  };
126	
127	  const passwordChecks = [
128	    { label: "At least 8 characters", met: newPassword.length >= 8 },
129	    { label: "Uppercase letter", met: /[A-Z]/.test(newPassword) },
130	    { label: "Lowercase letter", met: /[a-z]/.test(newPassword) },
131	    { label: "Number", met: /[0-9]/.test(newPassword) },
132	    { label: "Special character (!@#$...)", met: /[^A-Za-z0-9]/.test(newPassword) },
133	  ];
134	
135	  const handleChangePassword = async () => {
136	    if (newPassword !== confirmPassword) {
137	      toast({ title: "Passwords don't match", description: "New password and confirmation must match.", variant: "destructive" });
138	      return;
139	    }
140	    if (!passwordChecks.every((c) => c.met)) {
141	      toast({ title: "Weak password", description: "Please meet all password requirements.", variant: "destructive" });
142	      return;
143	    }
144	
145	    try {
146	      setChangingPassword(true);
147	      const { error } = await supabase.auth.updateUser({ password: newPassword });
148	      if (error) throw error;
149	
150	      toast({ title: "Password updated", description: "Your password has been changed successfully." });
151	      setShowChangePassword(false);
152	      setCurrentPassword("");
153	      setNewPassword("");
154	      setConfirmPassword("");
155	    } catch (error: any) {
156	      toast({ title: "Failed to update password", description: error.message || "Something went wrong.", variant: "destructive" });
157	    } finally {
158	      setChangingPassword(false);
159	    }
160	  };
161	
162	  const handleSignOutAllDevices = async () => {
163	    try {
164	      setSigningOut(true);
165	      const { error } = await supabase.auth.signOut({ scope: "global" });
166	      if (error) throw error;
167	      toast({ title: "Signed out everywhere", description: "All sessions have been terminated." });
168	      window.location.href = "/auth";
169	    } catch (error: any) {
170	      toast({ title: "Error", description: error.message, variant: "destructive" });
171	    } finally {
172	      setSigningOut(false);
173	      setShowSignOutAll(false);
174	    }
175	  };
176	
177	  const strength = getPasswordStrength(newPassword);
178	
179	  return (
180	    <div className="space-y-6">
181	      {/* Change Password */}
182	      <Card className="p-4 md:p-8">
183	        <div className="flex items-center gap-3 mb-1">
184	          <KeyRound className="w-5 h-5 text-bronze" />
185	          <h2 className="font-vollkorn text-xl md:text-2xl font-bold">Password</h2>
186	        </div>
187	        <p className="text-sm text-muted-foreground mb-5">
188	          Keep your account secure with a strong, unique password.
189	        </p>
190	
191	        {!showChangePassword ? (
192	          <Button
193	            variant="outline"
194	            onClick={() => setShowChangePassword(true)}
195	            className="gap-2"
196	          >
197	            <Lock className="w-4 h-4" /> Change Password
198	          </Button>
199	        ) : (
200	          <div className="space-y-4 max-w-md">
201	            {/* New Password */}
202	            <div>
203	              <Label htmlFor="newPassword" className="text-sm">New Password</Label>
204	              <div className="relative mt-1.5">
205	                <Input
206	                  id="newPassword"
207	                  type={showNew ? "text" : "password"}
208	                  value={newPassword}
209	                  onChange={(e) => setNewPassword(e.target.value)}
210	                  placeholder="Enter new password"
211	                  className="pr-10"
212	                />
213	                <button
214	                  type="button"
215	                  onClick={() => setShowNew(!showNew)}
216	                  className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
217	                >
218	                  {showNew ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
219	                </button>
220	              </div>
221	
222	              {newPassword && (
223	                <div className="mt-3 space-y-2">
224	                  {/* Strength bar */}
225	                  <div className="flex items-center gap-2">
226	                    <div className="flex-1 h-1.5 bg-muted rounded-full overflow-hidden">
227	                      <div
228	                        className={`h-full rounded-full transition-all duration-300 ${strength.bg}`}
229	                        style={{
230	                          width: `${(passwordChecks.filter((c) => c.met).length / passwordChecks.length) * 100}%`,
231	                        }}
232	                      />
233	                    </div>
234	                    <span className={`text-xs font-medium ${strength.color}`}>{strength.label}</span>
235	                  </div>
236	
237	                  {/* Checklist */}
238	                  <ul className="space-y-1">
239	                    {passwordChecks.map((check) => (
240	                      <li key={check.label} className="flex items-center gap-2 text-xs">
241	                        {check.met ? (
242	                          <CheckCircle2 className="w-3.5 h-3.5 text-emerald-500" />
243	                        ) : (
244	                          <AlertTriangle className="w-3.5 h-3.5 text-muted-foreground" />
245	                        )}
246	                        <span className={check.met ? "text-foreground" : "text-muted-foreground"}>
247	                          {check.label}
248	                        </span>
249	                      </li>
250	                    ))}
251	                  </ul>
252	                </div>
253	              )}
254	            </div>
255	
256	            {/* Confirm Password */}
257	            <div>
258	              <Label htmlFor="confirmPassword" className="text-sm">Confirm New Password</Label>
259	              <div className="relative mt-1.5">
260	                <Input
261	                  id="confirmPassword"
262	                  type={showConfirm ? "text" : "password"}
263	                  value={confirmPassword}
264	                  onChange={(e) => setConfirmPassword(e.target.value)}
265	                  placeholder="Confirm new password"
266	                  className="pr-10"
267	                />
268	                <button
269	                  type="button"
270	                  onClick={() => setShowConfirm(!showConfirm)}
271	                  className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
272	                >
273	                  {showConfirm ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
274	                </button>
275	              </div>
276	              {confirmPassword && newPassword !== confirmPassword && (
277	                <p className="text-xs text-destructive mt-1">Passwords do not match</p>
278	              )}
279	            </div>
280	
281	            <div className="flex gap-3 pt-1">
282	              <Button
283	                onClick={handleChangePassword}
284	                disabled={changingPassword || !passwordChecks.every((c) => c.met) || newPassword !== confirmPassword}
285	                className="bg-bronze hover:bg-bronze-dark"
286	              >
287	                {changingPassword ? "Updating..." : "Update Password"}
288	              </Button>
289	              <Button
290	                variant="ghost"
291	                onClick={() => {
292	                  setShowChangePassword(false);
293	                  setNewPassword("");
294	                  setConfirmPassword("");
295	                }}
296	              >
297	                Cancel
298	              </Button>
299	            </div>
300	          </div>
301	        )}
302	      </Card>
303	
304	      {/* Two-Factor Authentication
305	      <Card className="p-4 md:p-8">
306	        <div className="flex items-center gap-3 mb-1">
307	          <Smartphone className="w-5 h-5 text-bronze" />
308	          <h2 className="font-vollkorn text-xl md:text-2xl font-bold">Two-Factor Authentication</h2>
309	        </div>
310	        <p className="text-sm text-muted-foreground mb-5">
311	          Add an extra layer of protection. Even if your password is compromised, your account stays safe.
312	        </p>
313	
314	        <div className="space-y-5">
315	          <div className="flex items-start md:items-center justify-between gap-3">
316	            <div className="flex-1 min-w-0">
317	              <div className="flex items-center gap-2">
318	                <Label className="text-sm md:text-base">Authenticator App</Label>
319	                {twoFactorEnabled ? (
320	                  <Badge variant="outline" className="text-primary border-primary/30 text-[10px]">Active</Badge>
321	                ) : (
322	                  <Badge variant="outline" className="text-muted-foreground text-[10px]">Not set up</Badge>
323	                )}
324	              </div>
325	              <p className="text-xs md:text-sm text-muted-foreground mt-0.5">
326	                Use Google Authenticator, Authy, or any TOTP app to generate verification codes.
327	              </p>
328	            </div>
329	            <Switch
330	              checked={twoFactorEnabled}
331	              onCheckedChange={(checked) => {
332	                setTwoFactorEnabled(checked);
333	                toast({
334	                  title: checked ? "2FA enabled (demo)" : "2FA disabled (demo)",
335	                  description: "Full authenticator setup coming soon.",
336	                });
337	              }}
338	              className="flex-shrink-0"
339	            />
340	          </div>
341	        </div>
342	      </Card> */}
343	
344	
345	      {/* Two-Factor Authentication */}
346	      <Card className="p-4 md:p-8">
347	        <div className="flex items-center gap-3 mb-1">
348	          <Smartphone className="w-5 h-5 text-bronze" />
349	          <h2 className="font-vollkorn text-xl md:text-2xl font-bold">Two-Factor Authentication</h2>
350	        </div>
351	        <p className="text-sm text-muted-foreground mb-5">
352	          Add an extra layer of protection. Every sign-in will require a code sent to your email.
353	        </p>
354	
355	        {twoFaView === "idle" && (
356	          <div className="flex items-start md:items-center justify-between gap-3">
357	            <div className="flex-1 min-w-0">
358	              <div className="flex items-center gap-2 mb-0.5">
359	                <Label className="text-sm md:text-base">Email Verification Code</Label>
360	                {twoFactorEnabled ? (
361	                  <Badge variant="outline" className="text-primary border-primary/30 text-[10px]">Active</Badge>
362	                ) : (
363	                  <Badge variant="outline" className="text-muted-foreground text-[10px]">Not set up</Badge>
364	                )}
365	              </div>
366	              <p className="text-xs md:text-sm text-muted-foreground">
367	                {twoFactorEnabled
368	                  ? "A 6-digit code is sent to your email each time you sign in."
369	                  : "We'll send a 6-digit code to your email each time you sign in. No app required."}
370	              </p>
371	            </div>
372	            {twoFactorEnabled ? (
373	              <Button
374	                variant="outline"
375	                size="sm"
376	                onClick={() => setTwoFaView("disabling")}
377	                className="flex-shrink-0 text-destructive border-destructive/30 hover:bg-destructive/10"
378	              >
379	                Disable
380	              </Button>
381	            ) : (
382	              <Button
383	                size="sm"
384	                onClick={() => setTwoFaView("setup")}
385	                className="flex-shrink-0 bg-bronze hover:bg-bronze/90 text-background"
386	              >
387	                Enable
388	              </Button>
389	            )}
390	          </div>
391	        )}
392	
393	        {twoFaView === "setup" && (
394	          <div className="mt-2">
395	            <MFASetup
396	              onComplete={() => {
397	                setTwoFactorEnabled(true);
398	                setTwoFaView("idle");
399	                toast({ title: "2FA Enabled!", description: "Your account is now secured with two-factor authentication." });
400	              }}
401	              onSkip={() => setTwoFaView("idle")}
402	            />
403	          </div>
404	        )}
405	
406	        {twoFaView === "disabling" && (
407	          <div className="mt-4 p-4 rounded-xl border border-destructive/20 bg-destructive/5 space-y-4">
408	            <div className="flex items-center gap-2 text-sm text-destructive font-medium">
409	              <AlertTriangle className="w-4 h-4" />
410	              Disable Two-Factor Authentication
411	            </div>
412	            <p className="text-xs text-muted-foreground">
413	              We'll send a verification code to <span className="font-medium text-foreground">{twoFaEmail}</span> to confirm this action.
414	            </p>
415	            <div className="flex gap-2">
416	              <Button
417	                size="sm"
418	                onClick={startDisable2FA}
419	                disabled={twoFaSending}
420	                className="bg-destructive hover:bg-destructive/90 text-background"
421	              >
422	                {twoFaSending ? <Loader2 className="w-4 h-4 animate-spin mr-1" /> : <Mail className="w-4 h-4 mr-1" />}
423	                Send Code
424	              </Button>
425	              <Button size="sm" variant="ghost" onClick={() => setTwoFaView("idle")}>Cancel</Button>
426	            </div>
427	          </div>
428	        )}
429	
430	        {twoFaView === "disabling-sent" && (
431	          <div className="mt-4 p-4 rounded-xl border border-destructive/20 bg-destructive/5 space-y-4">
432	            <p className="text-sm text-muted-foreground">
433	              Enter the 6-digit code sent to <span className="font-medium text-foreground">{twoFaEmail}</span>
434	            </p>
435	            <div className="flex justify-start">
436	              <InputOTP
437	                maxLength={6}
438	                value={twoFaDisableCode}
439	                onChange={setTwoFaDisableCode}
440	                onComplete={confirmDisable2FA}
441	                autoFocus
442	              >
443	                <InputOTPGroup>
444	                  <InputOTPSlot index={0} />
445	                  <InputOTPSlot index={1} />
446	                  <InputOTPSlot index={2} />
447	                  <InputOTPSlot index={3} />
448	                  <InputOTPSlot index={4} />
449	                  <InputOTPSlot index={5} />
450	                </InputOTPGroup>
451	              </InputOTP>
452	            </div>
453	            <div className="flex gap-2">
454	              <Button
455	                size="sm"
456	                onClick={confirmDisable2FA}
457	                disabled={twoFaDisabling || twoFaDisableCode.length !== 6}
458	                className="bg-destructive hover:bg-destructive/90 text-background"
459	              >
460	                {twoFaDisabling && <Loader2 className="w-4 h-4 animate-spin mr-1" />}
461	                Confirm Disable
462	              </Button>
463	              <button
464	                onClick={startDisable2FA}
465	                disabled={twoFaSending}
466	                className="text-xs text-muted-foreground hover:text-foreground transition-colors px-2"
467	              >
468	                {twoFaSending ? "Sending..." : "Resend code"}
469	              </button>
470	              <Button size="sm" variant="ghost" onClick={() => { setTwoFaView("idle"); setTwoFaDisableCode(""); }}>
471	                Cancel
472	              </Button>
473	            </div>
474	          </div>
475	        )}
476	      </Card>
477	
478	
479	
480	
481	
482	
483	      {/* Session Security */}
484	      <Card className="p-4 md:p-8">
485	        <div className="flex items-center gap-3 mb-1">
486	          <Shield className="w-5 h-5 text-bronze" />
487	          <h2 className="font-vollkorn text-xl md:text-2xl font-bold">Session & Login Security</h2>
488	        </div>
489	        <p className="text-sm text-muted-foreground mb-5">
490	          Monitor and control your active sessions across all devices.
491	        </p>
492	
493	        <div className="space-y-5">
494	          <div className="flex items-start md:items-center justify-between gap-3">
495	            <div className="flex-1 min-w-0">
496	              <Label className="text-sm md:text-base">Login Alerts</Label>
497	              <p className="text-xs md:text-sm text-muted-foreground mt-0.5">
498	                Get notified when someone signs into your account from a new device or location.
499	              </p>
500	            </div>
501	            <Switch
502	              checked={loginAlertsEnabled}
503	              onCheckedChange={(checked) => {
504	                setLoginAlertsEnabled(checked);
505	                toast({
506	                  title: checked ? "Login alerts enabled" : "Login alerts disabled",
507	                  description: checked
508	                    ? "You'll be notified of new sign-ins."
509	                    : "You won't be notified of new sign-ins.",
510	                });
511	              }}
512	              className="flex-shrink-0"
513	            />
514	          </div>
515	
516	          <Separator />
517	
518	          <div>
519	            <Label className="text-sm md:text-base text-destructive">Sign Out All Devices</Label>
520	            <p className="text-xs md:text-sm text-muted-foreground mt-0.5 mb-3">
521	              End all active sessions everywhere. You'll need to sign in again on every device.
522	            </p>
523	            <Button
524	              variant="destructive"
525	              size="sm"
526	              onClick={() => setShowSignOutAll(true)}
527	              className="gap-2"
528	            >
529	              <LogOut className="w-4 h-4" /> Sign Out Everywhere
530	            </Button>
531	          </div>
532	        </div>
533	      </Card>
534	
535	      {/* Sign out confirmation dialog */}
536	      <Dialog open={showSignOutAll} onOpenChange={setShowSignOutAll}>
537	        <DialogContent>
538	          <DialogHeader>
539	            <DialogTitle className="flex items-center gap-2">
540	              <AlertTriangle className="w-5 h-5 text-destructive" />
541	              Sign Out All Devices?
542	            </DialogTitle>
543	            <DialogDescription>
544	              This will terminate all your active sessions across every device and browser. You'll be signed out immediately and will need to log in again.
545	            </DialogDescription>
546	          </DialogHeader>
547	          <DialogFooter className="gap-2 sm:gap-0">
548	            <Button variant="ghost" onClick={() => setShowSignOutAll(false)}>
549	              Cancel
550	            </Button>
551	            <Button
552	              variant="destructive"
553	              onClick={handleSignOutAllDevices}
554	              disabled={signingOut}
555	            >
556	              {signingOut ? "Signing out..." : "Yes, sign out everywhere"}
557	            </Button>
558	          </DialogFooter>
559	        </DialogContent>
560	      </Dialog>
561	    </div>
562	  );
563	};
564	
565	export default SecurityTab;
