            tax_id: "", default_currency: "KES",
            default_tax_rate: 0,
            default_payment_terms: "Payment is due within 30 days of invoice date.",
          });
        }
      }
    } finally {
      if (!cancelled) setSettingsLoading(false);
    }
  })();

  return () => { cancelled = true; };
}, [open, editingInvoice]);

