                <p className="text-xs text-muted-foreground">Temporarily disable all alerts</p>
              </div>
            </div>
            <Switch id="muteAll" checked={settings.muteAll} onCheckedChange={() => toggle("muteAll")} />
          </div>
        </Card>
      </div>
    </div>
  );
};

export default Notifications;

